const content = $input.item.json.message.content;
let data;
try {
  const match = content.match(/\{[\s\S]*\}/);
  data = JSON.parse(match[0]);
} catch(e) { data = { matches: [] }; }
const offre = $('Normaliser offre').item.json;
const offreInfo = $('Enregistrer offre').item.json;
const matches = (data.matches || []).filter(m => m.score >= 50);
return [{ json: { matches, nb_matches: matches.length, intitule: offre.intitule, entreprise: offre.entreprise, type_contrat: offre.type_contrat, duree: offre.duree, offre_id: offreInfo.id } }];
